 wire signed [31:0] signedB = B; 
 always @(*) begin 
  if (enable) 
  case (ctrl) 
  2'b00: 
  dout = B << SHIFT_AMOUNT; 
  2'b01: 
  dout = B >> SHIFT_AMOUNT; 
  2'b11: 
  dout = signedB >>> SHIFT_AMOUNT; 
  default: 
  dout = B; 
  endcase 
  else 
  dout = B; 
 end 
 endmodule

