);
    output [31:0] readdata;
    input  [9:0] address;
    input  [3:0] byteenable;
    input        chipselect;
    input        clk;
    input        clken;
    input        write;
    input  [31:0] writedata;

    reg [31:0] ram [0:1023]; 
    reg [31:0] readdata;
    wire       wren;
    assign wren = chipselect & write;

    always @(posedge clk) begin
        if (clken) begin
