  FIRE = 1, 
  COUNT = 2; 
  reg [1:0] state, next_state; 
  reg [25:0] count; 
  always @ (posedge clk or negedge reset_n) 
  state <= (!reset_n) ? WAIT : next_state; 
  always @ (posedge clk or negedge reset_n) begin 
  if (!reset_n) begin 
  debounce <= 0; 
  count <= 0; 
  end 
  else begin 
  debounce <= 0; 
  count <= 0; 
  case (state) 
  WAIT: begin 
  end 
