  case (state) 
  WAIT: next_state = (button) ? FIRE : state; 
  FIRE: next_state = COUNT; 
  COUNT: next_state = (count > COUNT_VALUE - 1) ? WAIT : state; 
  default: next_state = WAIT; 
  endcase 
