  input [2:0] sel;
  input [1:0] in5;
  input [1:0] in4;
  input [1:0] in3;
  input [1:0] in2;
  input [1:0] in1;
  input [1:0] in0;
  //wire [5:0] select;
  reg  [5:0] sl;
  wire [5:0] slb;

  always @(sel) begin
    case (sel)  // synopsys parallel_case
