module mg_10155 (input clk,input rst,input key1_press,input key2_press,input key3_press,input key4_press,output reg [1:0]game_status,input hit_wall,input hit_body,output reg die_flash,output reg restart);
localparam RESTART = 2'b00; 
  localparam START = 2'b01; 
  localparam PLAY = 2'b10; 
  localparam DIE = 2'b11; 
  reg[31:0]clk_cnt; 
  always@(posedge clk or negedge rst) 
  begin 
  if(!rst) begin 
  game_status <= START; 
  clk_cnt <= 0; 
  die_flash <= 1; 
  restart <= 0; 
  end 
  else begin 
  case(game_status) 
  RESTART:begin 
  if(clk_cnt <= 5) begin 
  clk_cnt <= clk_cnt + 1; 
  restart <= 1; 
  end 
  else begin 
  game_status <= START; 
  clk_cnt <= 0; 
  restart <= 0; 
  end 
  end 
  START:begin 
  if (key1_press | key2_press | key3_press | key4_press) 
  game_status <= PLAY; 
  else 
  game_status <= START; 
  end 
  PLAY:begin 
  if(hit_wall | hit_body) 
  game_status <= DIE; 
  else 
  game_status <= PLAY; 
  end 
  DIE:begin 
  die_flash <= 1; 
  clk_cnt <= 0; 
  game_status <= RESTART; 
  end 
  endcase 
  end 
  end 
 endmodule

