module origen_021960(
    output reg clok,
    output reg [5:0] cheker,
    output reg [5:0] contador,
    output reg [5:0] contador2,
    output reg bandera,
    output reg bandera2,
    output reg reset_L,
    output reg selector,
    output reg [1:0] data_in0,
    output reg [1:0] data_in1,
    input [1:0] data_out,
    input [1:0] data_out_sintetizado,
    input [1:0] data_out_Est
);

    initial begin
        $dumpfile("Mux.vcd");
        $dumpvars;

        {clok, cheker, contador, contador2, bandera, bandera2, reset_L, selector, data_in0, data_in1} <= 0;

        @(posedge clok);
        reset_L <= 1;

        repeat(16) begin
            @(posedge clok);
            selector <= ~selector;
            data_in0 <= data_in0 + 1;
            data_in1 <= data_in1 - 1;

            if (data_out != data_out_Est)
                cheker <= cheker + 1;

            if (data_out[0] == 1 && ~bandera) begin
                contador <= contador + 1;
                bandera <= 1;
            end
            else if (data_out[0] == 0) begin
                bandera <= 0;
            end

            if (data_out[1] == 1 && ~bandera2) begin
                contador2 <= contador2 + 1;
                bandera2 <= 1;
            end
            else if (data_out[1] == 0) begin
                bandera2 <= 0;
            end
        end

        @(posedge clok);
        {cheker, contador, contador2, bandera, bandera2, reset_L, selector, data_in0, data_in1} <= 0;

        #2 $finish;
    end

    always #1 clok <= ~clok;

endmodule

