module origen_026124(
    input [3:0] X,
    input [3:0] Y,
    output reg XlessthanY,
    output reg XequalY,
    output reg XgreaterthanY
);

always @(X or Y) begin
    if (X > Y) begin
        XgreaterthanY = 1'b1;
        XequalY = 1'b0;
        XlessthanY = 1'b0;
    end
    else if (X == Y) begin
        XgreaterthanY = 1'b0;
        XequalY = 1'b1;
        XlessthanY = 1'b0;
    end
    else begin
        XgreaterthanY = 1'b0;
        XequalY = 1'b0;
        XlessthanY = 1'b1;
    end
end

endmodule

module testbench_Comparator();
    reg [3:0] X, Y;
    wire XlessthanY, XequalY, XgreaterthanY;

    four_bit_Comparator uut (
        .X(X),
        .Y(Y),
        .XlessthanY(XlessthanY),
        .XequalY(XequalY),
        .XgreaterthanY(XgreaterthanY)
    );

    initial begin
        X = 4'b0110; Y = 4'b1001; // X = 6, Y = 9
        #30;
        X = 4'b1100; Y = 4'b0111; // X = 12, Y = 7
        #30;
        X = 4'b1000; Y = 4'b1000; // X = 8, Y = 8
        #30;
        $finish;
    end

