    assign data_out_i = data_out_reg;
    assign data_out = data_out_i;

    // Scan D-Flip-Flop replacement
    reg [NUM_IOS-1:0] scan_data_out_reg;
    always @(posedge clk) begin
        if (scan_select_in_i)
            scan_data_out_reg <= module_data_out;
        else
            scan_data_out_reg <= scan_data_in;
    end

    assign scan_data_out = scan_data_out_reg;
    assign module_data_in = scan_data_out;

    // User module logic replacement
    reg [NUM_IOS-1:0] user_module_io;

    always @(posedge latch_enable_in_i) begin
        user_module_io <= module_data_in;
    end

    assign module_data_out = user_module_io;

endmodule

