  active3 <= 1'b0; 
  sign_result0 <= 1'b0; 
  sign_result1 <= 1'b0; 
  sign_result2 <= 1'b0; 
  sign_result3 <= 1'b0; 
  end 
  else if(~stall) begin 
  A <= sign_a ? -a_sign_ext : a_sign_ext; 
  B <= sign_b ? -b_sign_ext : b_sign_ext; 
  sign_result0 <= sign_a ^ sign_b; 
  active0 <= enable_op; 
  result_ll_0 <= A[15:0] * B[15:0]; 
  result_lh_0 <= A[15:0] * B[32:16]; 
