          key_mem[27] <= 8'h00;
          key_mem[28] <= 8'h00;
          key_mem[29] <= 8'h00;
          key_mem[30] <= 8'h00;
          key_mem[31] <= 8'h00;
          size_reg    <= 0;
        end
      else
        begin
          if (key_write)
            begin
              key_mem[key_write_addr] <= key_write_data;
            end

          if (init)
            begin
              size_reg <= key_size;
            end
        end
    end

  always @*
    begin
      reg [4 : 0] addr;
      if (size_reg)
        addr = key_read_addr;
      else
        addr = {1'b0, key_read_addr[3 : 0]};
      tmp_key_read_data = key_mem[addr];
    end

endmodule

