module origen_028261(
    inout sda,
    input scl,
    input [6:0] slave_addrs,
    output reg [7:0] curr_data
);

    reg SDA_shadow;
    reg start_or_stop;
    reg incycle;
    reg [3:0] bitcnt;
    reg bit_DATA, bit_ACK;
    reg data_phase;
    reg adr_match;
    reg op_read, op_write;
    reg [7:0] mem;
    reg got_ACK;

    wire sda_in;
    reg sda_out;
    reg sda_oe;

    // Xilinx-specific I/O buffer
    `ifdef XILINX
        IOBUF sda_buf (.IO(sda), .I(sda_out), .O(sda_in), .T(!sda_oe));
    `else
        assign sda = sda_oe ? sda_out : 1'bz;
        assign sda_in = sda;
    `endif

    // Start/Stop detection
    always @(posedge scl) begin
        SDA_shadow <= sda_in;
        start_or_stop <= SDA_shadow ^ sda_in;
    end

    // Cycle management
    always @(negedge scl or posedge start_or_stop) begin
        if (start_or_stop)
            incycle <= 0;
        else if (!sda_in && !incycle)
            incycle <= 1;
    end

    // Bit counter and phase tracking
    always @(negedge scl or posedge start_or_stop) begin
        if (start_or_stop) begin
            bitcnt <= 0;
            data_phase <= 0;
        end else if (incycle) begin
            bitcnt <= bitcnt + 1;
            if (bitcnt == 4'b1000) begin
                bitcnt <= 0;
                data_phase <= adr_match;
            end
        end
    end

    always @(*) begin
        bit_DATA = (bitcnt < 4'b1000);
        bit_ACK = (bitcnt == 4'b1000);
    end

    // Address matching and operation determination
    always @(posedge scl) begin
        if (bit_DATA && !data_phase) begin
            adr_match <= (bitcnt < 4'b0111) ? (slave_addrs[6-bitcnt] == sda_in) : adr_match;
            if (bitcnt == 4'b0111) begin
                op_read <= sda_in & adr_match;
                op_write <= !sda_in & adr_match;
            end
        end
    end

    // Data handling
    always @(posedge scl) begin
        if (bit_DATA && data_phase && op_write)
            mem[7-bitcnt] <= sda_in;
    end

    // ACK handling
    always @(posedge scl) begin
        if (bit_ACK)
            got_ACK <= !sda_in;
    end

    // SDA control
    always @(*) begin
        sda_oe = 0;
        sda_out = 1;
        if (bit_ACK && (adr_match || (data_phase && op_write))) begin
            sda_oe = 1;
            sda_out = 0;
        end else if (bit_DATA && data_phase && op_read) begin
            sda_oe = 1;
            sda_out = mem[7-bitcnt];
        end
    end

    // Output current data
    always @(posedge scl) begin
        curr_data <= mem;
    end

endmodule

