`timescale 1ns / 1ps

// Operation macros
`define OP_ADD 4'b0000
`define OP_SUB 4'b0001
`define OP_MUL 4'b0010
`define OP_DIV 4'b0011
`define OP_SHIFT_LEFT 4'b0100
`define OP_SHIFT_RIGHT 4'b0101
`define OP_ROTATE_LEFT 4'b0110
`define OP_ROTATE_RIGHT 4'b0111
`define OP_AND 4'b1000
`define OP_OR 4'b1001
`define OP_XOR 4'b1010
`define OP_NOR 4'b1011
`define OP_NAND 4'b1100
`define OP_XNOR 4'b1101
`define OP_GT 4'b1110
`define OP_EQ 4'b1111

module origen_116433(
    input [7:0] a,
    input [7:0] b,
    input [3:0] op,
    output reg [7:0] out,
    output reg carry
);

    reg [8:0] result;

    always @(*) begin
        case(op)
            `OP_ADD: result = a + b;
            `OP_SUB: result = a - b;
            `OP_MUL: result = a * b;
            `OP_DIV: result = a / b;
            `OP_SHIFT_LEFT: result = a << 1;
            `OP_SHIFT_RIGHT: result = a >> 1;
            `OP_ROTATE_LEFT: result = {a[6:0], a[7]};
            `OP_ROTATE_RIGHT: result = {a[0], a[7:1]};
            `OP_AND: result = a & b;
            `OP_OR: result = a | b;
            `OP_XOR: result = a ^ b;
            `OP_NOR: result = ~(a | b);
            `OP_NAND: result = ~(a & b);
            `OP_XNOR: result = ~(a ^ b);
            `OP_GT: result = (a > b) ? 8'b1 : 8'b0;
            `OP_EQ: result = (a == b) ? 8'b1 : 8'b0;
            default: result = 9'b0;
        endcase

        out = result[7:0];
        carry = (op == `OP_ADD) ? result[8] : 1'b0;
    end
endmodule

module testbench;
    reg [7:0] a, b;
    reg [3:0] op;
    wire [7:0] out;
    wire carry;

    alu8bit uut (
        .a(a),
        .b(b),
        .op(op),
        .out(out),
        .carry(carry)
    );

    initial begin
        $display("Starting ALU testbench");
        a = 8'h0A;
        b = 8'h05;

        for (op = 0; op < 16; op = op + 1) begin
            #10;
            $display("Op: %b, A: %h, B: %h, Out: %h, Carry: %b", op, a, b, out, carry);
        end

        // Test equality comparison
        a = 8'h0A;
        b = 8'h0A;
        op = `OP_EQ;
        #10;
        $display("Equality test: A: %h, B: %h, Out: %h", a, b, out);

        // Assert equality comparison result
        if (out !== 8'h01) begin
            $display("Assertion failed: Expected 1 for equality comparison");
        end else begin
            $display("Assertion passed: Equality comparison successful");
        end

        $display("ALU testbench completed");
        $finish;
    end
endmodule

