module origen_105063(
    input [31:0] in,
    output [31:0] out
);

    wire [7:0] a0, a1, a2, a3;
    wire [7:0] b0, b1, b2, b3;

    assign {a0, a1, a2, a3} = in;

    GF_Mul_e gfm_e0(.in(a0), .out(b0));
    GF_Mul_b gfm_b0(.in(a1), .out(b1));
    GF_Mul_d gfm_d0(.in(a2), .out(b2));
    GF_Mul_9 gfm_90(.in(a3), .out(b3));
    assign out[31:24] = b0 ^ b1 ^ b2 ^ b3;

    GF_Mul_9 gfm_91(.in(a0), .out(b0));
    GF_Mul_e gfm_e1(.in(a1), .out(b1));
    GF_Mul_b gfm_b1(.in(a2), .out(b2));
    GF_Mul_d gfm_d1(.in(a3), .out(b3));
    assign out[23:16] = b0 ^ b1 ^ b2 ^ b3;

    GF_Mul_d gfm_d2(.in(a0), .out(b0));
    GF_Mul_9 gfm_92(.in(a1), .out(b1));
    GF_Mul_e gfm_e2(.in(a2), .out(b2));
    GF_Mul_b gfm_b2(.in(a3), .out(b3));
    assign out[15:8] = b0 ^ b1 ^ b2 ^ b3;

