module autovcoder_063682 #(
    parameter num_leaves = 32,
    parameter payload_sz = $clog2(num_leaves) + 4,
    parameter p_sz = 1 + $clog2(num_leaves) + payload_sz,  //packet size
    parameter addr = 1'b0,
    parameter level = 1
) (
    input clk,
    input reset,
    input [p_sz*16-1:0] pe_interface,
    output [p_sz*16-1:0] interface_pe,
    output [16-1:0] resend,
    input [1*4*p_sz-1:0] bus_i,

    output [1*4*p_sz-1:0] bus_o
);

  wire [4*p_sz-1:0] switch_left;
  wire [4*p_sz-1:0] switch_right;
  wire [4*p_sz-1:0] left_switch;
  wire [4*p_sz-1:0] right_switch;
  wire [4*p_sz-1:0] switch_left_0;
  wire [4*p_sz-1:0] switch_right_0;
  wire [4*p_sz-1:0] left_switch_0;
  wire [4*p_sz-1:0] right_switch_0;



  pipe_ff #(
      .data_width(4 * p_sz)
  ) pipe_ff_inst_sl_0 (
      .clk  (clk),
      .reset(reset),
      .din  (switch_left_0),
      .dout (switch_left)
  );
  pipe_ff #(
      .data_width(4 * p_sz)
  ) pipe_ff_inst_sr_0 (
      .clk  (clk),
      .reset(reset),
      .din  (switch_right_0),
      .dout (switch_right)
  );
  pipe_ff #(
      .data_width(4 * p_sz)
  ) pipe_ff_inst_ls_0 (
      .clk  (clk),
      .reset(reset),
      .din  (left_switch_0),
      .dout (left_switch)
  );
  pipe_ff #(
      .data_width(4 * p_sz)
  ) pipe_ff_inst_rs_0 (
      .clk  (clk),
      .reset(reset),
      .din  (right_switch_0),
      .dout (right_switch)
  );




  t_cluster #(
      .num_leaves(num_leaves),
      .payload_sz(payload_sz),
      .addr(addr),
      .level(level),
      .p_sz(p_sz),
      .num_switches(4)
  ) t_lvl1 (
      .clk(clk),
      .reset(reset),
      .u_bus_i(bus_i),
      .u_bus_o(bus_o),
      .l_bus_i(left_switch),
      .r_bus_i(right_switch),
      .l_bus_o(switch_left_0),
      .r_bus_o(switch_right_0)
  );

  subtree_212 #(
      .num_leaves(num_leaves),
      .payload_sz(payload_sz),
      .addr({addr, 1'b0}),
      .p_sz(p_sz)
  ) subtree_left (
      .clk(clk),
      .reset(reset),
      .bus_i(switch_left),
      .bus_o(left_switch_0),
      .pe_interface(pe_interface[p_sz*8-1:0]),
      .interface_pe(interface_pe[p_sz*8-1:0]),
      .resend(resend[8-1:0])
  );

  subtree_212 #(
      .num_leaves(num_leaves),
      .payload_sz(payload_sz),
      .addr({addr, 1'b1}),
      .p_sz(p_sz)
  ) subtree_right (
      .clk(clk),
      .reset(reset),
      .bus_i(switch_right),
      .bus_o(right_switch_0),
      .pe_interface(pe_interface[p_sz*16-1:p_sz*8]),
      .interface_pe(interface_pe[p_sz*16-1:p_sz*8]),
      .resend(resend[16-1:8])
  );
endmodule

