        p5_r <= 0;
        p6_r <= 0;
        p7_r <= 0;
    end else if (iv & ~zce) begin
        p0_r <= phs[7:6];
        p1_r <= phs[5:4];
        p2_r <= phs[3:2];
        p3_r <= phs[1:0];
        p4_r <= phs[7:6];
        p5_r <= phs[5:4];
        p6_r <= phs[3:2];
        p7_r <= phs[1:0];
    end
