assign p1 = p1_r;
assign p2 = p2_r;
assign p3 = p3_r;
assign p4 = p4_r;
assign p5 = p5_r;
assign p6 = p6_r;
assign p7 = p7_r;
assign acsv = iv & ~zce;

// Internal functionality for TBM module
reg [7:0] d0_r, d1_r;
always @(posedge clk) begin
    if (first) begin
        d0_r <= 0;
        d1_r <= 0;
    end else if (acsv) begin
        d0_r <= p0_r + p1_r + p2_r + p3_r;
        d1_r <= p4_r + p5_r + p6_r + p7_r;
    end
end
assign d0 = d0_r;
assign d1 = d1_r;
assign symbols = { d1_r[7:0], d0_r[7:0] };
assign tbmv = acsv;

always @(posedge clk) begin
    readsym <= iord & s1;
end

assign data = {d1[7], d0[7], d1[6], d0[6], d1[5], d0[5], d1[4], d0[4], d1[3], d0[3], d1[2], d0[2], d1[1], d0[1], d1[0], d0[0]};
assign status = {tbmv, 5'b00000, symbols};
always @(posedge clk) omux <= ioaddr[1] ? status : data;
