module autovcoder_092619 (
    ap_clk,
    ap_rst,
    ap_start,
    ap_done,
    ap_continue,
    ap_idle,
    ap_ready,
    in_img_linestride,
    ap_return
);

  parameter ap_ST_fsm_state1 = 2'd1;
  parameter ap_ST_fsm_state2 = 2'd2;

  input ap_clk;
  input ap_rst;
  input ap_start;
  output ap_done;
  input ap_continue;
  output ap_idle;
  output ap_ready;
  input [31:0] in_img_linestride;
  output [31:0] ap_return;

  reg ap_done;
  reg ap_idle;
  reg ap_ready;

  reg    ap_done_reg;
  (* fsm_encoding = "none" *) reg   [1:0] ap_CS_fsm;
  wire    ap_CS_fsm_state1;
  reg   [0:0] tmp_reg_73;
  reg   [30:0] lshr_ln59_1_reg_78;
  reg   [30:0] lshr_ln59_2_reg_83;
  reg    ap_block_state1;
  wire   [31:0] sub_ln59_fu_28_p2;
  wire    ap_CS_fsm_state2;
  wire   [31:0] zext_ln59_fu_54_p1;
  wire   [31:0] sub_ln59_1_fu_57_p2;
  wire   [31:0] zext_ln59_1_fu_63_p1;
  reg   [1:0] ap_NS_fsm;
  reg    ap_ST_fsm_state1_blk;
  wire    ap_ST_fsm_state2_blk;
  wire    ap_ce_reg;

  // power-on initialization
  initial begin
    #0 ap_done_reg = 1'b0;
    #0 ap_CS_fsm = 2'd1;
  end

  always @(posedge ap_clk) begin
    if (ap_rst == 1'b1) begin
      ap_CS_fsm <= ap_ST_fsm_state1;
    end else begin
      ap_CS_fsm <= ap_NS_fsm;
    end
  end

  always @(posedge ap_clk) begin
    if (ap_rst == 1'b1) begin
      ap_done_reg <= 1'b0;
    end else begin
      if ((ap_continue == 1'b1)) begin
        ap_done_reg <= 1'b0;
      end else if ((1'b1 == ap_CS_fsm_state2)) begin
        ap_done_reg <= 1'b1;
      end
    end
  end

  always @(posedge ap_clk) begin
    if ((1'b1 == ap_CS_fsm_state1)) begin
      lshr_ln59_1_reg_78 <= {{sub_ln59_fu_28_p2[31:1]}};
      lshr_ln59_2_reg_83 <= {{in_img_linestride[31:1]}};
      tmp_reg_73 <= in_img_linestride[32'd31];
    end
  end

  always @(*) begin
    if (((ap_start == 1'b0) | (ap_done_reg == 1'b1))) begin
      ap_ST_fsm_state1_blk = 1'b1;
    end else begin
      ap_ST_fsm_state1_blk = 1'b0;
    end
  end

  assign ap_ST_fsm_state2_blk = 1'b0;

  always @(*) begin
    if ((1'b1 == ap_CS_fsm_state2)) begin
      ap_done = 1'b1;
    end else begin
      ap_done = ap_done_reg;
    end
  end

  always @(*) begin
    if (((ap_start == 1'b0) & (1'b1 == ap_CS_fsm_state1))) begin
      ap_idle = 1'b1;
    end else begin
      ap_idle = 1'b0;
    end
  end

  always @(*) begin
    if ((1'b1 == ap_CS_fsm_state2)) begin
      ap_ready = 1'b1;
    end else begin
      ap_ready = 1'b0;
    end
  end

  always @(*) begin
    case (ap_CS_fsm)
      ap_ST_fsm_state1: begin
        if ((~((ap_start == 1'b0) | (ap_done_reg == 1'b1)) & (1'b1 == ap_CS_fsm_state1))) begin
          ap_NS_fsm = ap_ST_fsm_state2;
        end else begin
          ap_NS_fsm = ap_ST_fsm_state1;
        end
      end
      ap_ST_fsm_state2: begin
        ap_NS_fsm = ap_ST_fsm_state1;
      end
      default: begin
        ap_NS_fsm = 'bx;
      end
    endcase
  end

  assign ap_CS_fsm_state1 = ap_CS_fsm[32'd0];

  assign ap_CS_fsm_state2 = ap_CS_fsm[32'd1];

  always @(*) begin
    ap_block_state1 = ((ap_start == 1'b0) | (ap_done_reg == 1'b1));
  end

  assign ap_return = ((tmp_reg_73[0:0] == 1'b1) ? sub_ln59_1_fu_57_p2 : zext_ln59_1_fu_63_p1);

  assign sub_ln59_1_fu_57_p2 = (32'd0 - zext_ln59_fu_54_p1);

  assign sub_ln59_fu_28_p2 = (32'd0 - in_img_linestride);

  assign zext_ln59_1_fu_63_p1 = lshr_ln59_2_reg_83;

  assign zext_ln59_fu_54_p1 = lshr_ln59_1_reg_78;

endmodule

