  reg [31:0] internal_data;
  reg [3:0] internal_we;
  reg [7:0] burst_counter;
  reg rdata_valid;

  always @(posedge s_axi_aclk) begin
    if(!s_axi_aresetn) begin
      s_axi_awready <= 0;
      s_axi_wready <= 0;
      s_axi_bid <= 0;
      s_axi_bresp <= 0;
      s_axi_bvalid <= 0;
      s_axi_arready <= 0;
      s_axi_rid <= 0;
      s_axi_rdata <= 0;
      s_axi_rresp <= 0;
      s_axi_rlast <= 0;
      s_axi_rvalid <= 0;
      bram_rst_a <= 0;
      bram_clk_a <= 0;
      bram_en_a <= 0;
      bram_we_a <= 0;
      bram_addr_a <= 0;
