      bram_clk_a <= s_axi_aclk;
      bram_en_a <= s_axi_awvalid || s_axi_arvalid;
      bram_we_a <= internal_we;
      bram_addr_a <= internal_addr;
      bram_wrdata_a <= internal_data;
    end
  end

