  input s_axi_wvalid,
  output reg s_axi_wready,
  output reg [1:0]s_axi_bresp,
  output reg s_axi_bvalid,
  input s_axi_bready,
  input [39:0]s_axi_araddr,
  input [7:0]s_axi_arlen,
  input [2:0]s_axi_arsize,
  input [1:0]s_axi_arburst,
  input [0:0]s_axi_arlock,
  input [3:0]s_axi_arcache,
  input [2:0]s_axi_arprot,
  input [3:0]s_axi_arregion,
  input [3:0]s_axi_arqos,
  input s_axi_arvalid,
  output reg s_axi_arready,
  output reg [31:0]s_axi_rdata,
  output reg [1:0]s_axi_rresp,
  output reg s_axi_rlast,
  output reg s_axi_rvalid,
  input s_axi_rready,
  output reg [39:0]m_axi_awaddr,
  output reg [2:0]m_axi_awprot,
  output reg m_axi_awvalid,
  input m_axi_awready,
  output reg [31:0]m_axi_wdata,
  output reg [3:0]m_axi_wstrb,
  output reg m_axi_wvalid,
  input m_axi_wready,
  input [1:0]m_axi_bresp,
  input m_axi_bvalid,
  output reg m_axi_bready,
  output reg [39:0]m_axi_araddr,
  output reg [2:0]m_axi_arprot,
  output reg m_axi_arvalid,
  input m_axi_arready,
  input [31:0]m_axi_rdata,
  input [1:0]m_axi_rresp,
  input m_axi_rvalid,
  output reg m_axi_rready
);

// Internal logic to handle the AXI protocol conversion
always @(posedge aclk or negedge aresetn) begin
  if (!aresetn) begin
    // Reset all outputs 
    s_axi_awready <= 0;
    s_axi_wready <= 0;
    s_axi_bresp <= 2'b00;
    s_axi_bvalid <= 0;
    s_axi_arready <= 0;
    s_axi_rdata <= 32'b0;
    s_axi_rresp <= 2'b00;
    s_axi_rlast <= 0;
    s_axi_rvalid <= 0;
    m_axi_awaddr <= 40'b0;
    m_axi_awprot <= 3'b0;
    m_axi_awvalid <= 0;
    m_axi_wdata <= 32'b0;
    m_axi_wstrb <= 4'b0;
    m_axi_wvalid <= 0;
    m_axi_bready <= 0;
    m_axi_araddr <= 40'b0;
    m_axi_arprot <= 3'b0;
    m_axi_arvalid <= 0;
    m_axi_rready <= 0;
  end
  else begin
    // Logic to handle AW channel
    if (s_axi_awvalid && !s_axi_awready) begin
      s_axi_awready <= 1;
      m_axi_awaddr <= s_axi_awaddr;
      m_axi_awprot <= s_axi_awprot;
      m_axi_awvalid <= 1;
    end else if (m_axi_awready && m_axi_awvalid) begin
      s_axi_awready <= 0;
      m_axi_awvalid <= 0;
    end

    // Logic to handle W channel
    if (s_axi_wvalid && !s_axi_wready) begin
      s_axi_wready <= 1;
      m_axi_wdata <= s_axi_wdata;
      m_axi_wstrb <= s_axi_wstrb;
      m_axi_wvalid <= 1;
      if (s_axi_wlast) begin
        s_axi_wready <= 0;
      end
    end else if (m_axi_wready && m_axi_wvalid) begin
      s_axi_wready <= 0;
      m_axi_wvalid <= 0;
    end

    // Logic to handle B channel
    if (!s_axi_bvalid && m_axi_bvalid) begin
      s_axi_bresp <= m_axi_bresp;
      s_axi_bvalid <= 1;
    end 
    if (s_axi_bready && s_axi_bvalid) begin
      s_axi_bvalid <= 0;
    end
    m_axi_bready <= (s_axi_bready && s_axi_bvalid);

    // Logic to handle AR channel
    if (s_axi_arvalid && !s_axi_arready) begin
      s_axi_arready <= 1;
      m_axi_araddr <= s_axi_araddr;
      m_axi_arprot <= s_axi_arprot;
      m_axi_arvalid <= 1;
    end else if (m_axi_arready && m_axi_arvalid) begin
      s_axi_arready <= 0;
      m_axi_arvalid <= 0;
    end

    // Logic to handle R channel
    if (!s_axi_rvalid && m_axi_rvalid) begin
      s_axi_rdata <= m_axi_rdata;
      s_axi_rresp <= m_axi_rresp;
      s_axi_rlast <= 1;
      s_axi_rvalid <= 1;
    end 
    if (s_axi_rready && s_axi_rvalid) begin
      s_axi_rvalid <= 0;
    end
    m_axi_rready <= (s_axi_rready && s_axi_rvalid);
  end
end

endmodule

