module autovcoder_123335 (
    CLOCK_50,  //	On Board 50 MHz
    // Your inputs and outputs here
    KEY,
    SW,
    // The ports below are for the VGA output.  Do not change.
    VGA_CLK,  //	VGA Clock
    VGA_HS,  //	VGA H_SYNC
    VGA_VS,  //	VGA V_SYNC
    VGA_BLANK_N,  //	VGA BLANK
    VGA_SYNC_N,  //	VGA SYNC
    VGA_R,  //	VGA Red[9:0]
    VGA_G,  //	VGA Green[9:0]
    VGA_B,  //	VGA Blue[9:0]
    LEDR,
    HEX3,
    HEX1
);

  input CLOCK_50;  //	50 MHz
  input [9:0] SW;
  input [3:0] KEY;

  // Declare your inputs and outputs here
  // Do not change the following outputs
  output VGA_CLK;  //	VGA Clock
  output VGA_HS;  //	VGA H_SYNC
  output VGA_VS;  //	VGA V_SYNC
  output VGA_BLANK_N;  //	VGA BLANK
  output VGA_SYNC_N;  //	VGA SYNC
  output [9:0] VGA_R;  //	VGA Red[9:0]
  output [9:0] VGA_G;  //	VGA Green[9:0]
  output [9:0] VGA_B;  //	VGA Blue[9:0]
  output [6:0] HEX3;
  output [6:0] HEX1;

  output [9:0] LEDR;  //test with leds

  wire [3:0] score1, score2;
  assign score1 = 4'd0;
  assign score2 = 4'd0;
  hex_decoder hex3 (
      score1,
      HEX3
  );
  hex_decoder hex0 (
      score2,
      HEX1
  );


  wire resetn;
  assign resetn = KEY[0];

  // Create the colour, x, y and writeEn wires that are inputs to the controller.
  wire [2:0] colour;
  wire [7:0] x;
  wire [6:0] y;
  wire writeEn, ld_top, ld_bottom, ld_left, ld_right, ld_color, enable;

  // Create an Instance of a VGA controller - there can be only one!
  // Define the number of colours as well as the initial background
  // image file (.MIF) for the controller.
  vga_adapter VGA (
      .resetn(resetn),
      .clock(CLOCK_50),
      .colour(colour),
      .x(x),
      .y(y),
      .plot(writeEn),
      /* Signals for the DAC to drive the monitor. */
      .VGA_R(VGA_R),
      .VGA_G(VGA_G),
      .VGA_B(VGA_B),
      .VGA_HS(VGA_HS),
      .VGA_VS(VGA_VS),
      .VGA_BLANK(VGA_BLANK_N),
      .VGA_SYNC(VGA_SYNC_N),
      .VGA_CLK(VGA_CLK)
  );
  defparam VGA.RESOLUTION = "160x120"; defparam VGA.MONOCHROME = "FALSE";
      defparam VGA.BITS_PER_COLOUR_CHANNEL = 1; defparam VGA.BACKGROUND_IMAGE = "black.mif";



  wire [7:0] x_p;
  wire [6:0] y_p;
  wire [2:0] color_p;
  process p0 (
      .clk(CLOCK_50),
      .enable(enable),
      .resetn(resetn),
      .ld_color(ld_color),
      .color_in(SW[9:7]),
      .x_out(x_p),
      .y_out(y_p),
      .color_out(color_p)
  );

  wire [7:0] x_b;
  wire [6:0] y_b;
  wire [2:0] color_b;
  border_datapath d0 (
      .clk(CLOCK_50),
      .enable(writeEn),
      .resetn(resetn),
      .ld_top(ld_top),
      .ld_bottom(ld_bottom),
      .ld_left(ld_left),
      .ld_right(ld_right),
      .x_out(x_b),
      .y_out(y_b),
      .color_out(color_b)
  );


  wire hold;
  control c0 (
      .clk(CLOCK_50),
      .resetn(resetn),
      .go(!KEY[1]),
      .ld_top(ld_top),
      .ld_bottom(ld_bottom),
      .ld_left(ld_left),
      .ld_right(ld_right),
      .writeEn(writeEn),
      .ld_color(ld_color),
      .enable(enable),
      .hold(hold)
  );
  assign LEDR[0] = ld_top;
  assign LEDR[1] = ld_bottom;
  assign LEDR[2] = ld_left;
  assign LEDR[3] = ld_right;
  assign LEDR[4] = enable;
  assign LEDR[9] = hold;


  reg [7:0] x_temp;
  reg [6:0] y_temp;
  reg [2:0] color_temp;
  always @(*) begin
    if (ld_color) begin
      x_temp = x_p;
      y_temp = y_p;
      color_temp = color_p;
    end else begin
      x_temp = x_b;
      y_temp = y_b;
      color_temp = color_b;
    end
  end

  assign x = x_temp;
  assign y = y_temp;
  assign colour = color_temp;

endmodule

