          oData1 <= 84'b0;
          oData2 <= 84'b0;
          oData3 <= 84'b0;
          oData4 <= 84'b0;
          oData5 <= 84'b0;
          oData6 <= 84'b0;
          oData7 <= 84'b0;
          state <= 2'b0;
        end
      endcase

      if (iWrreq) addr_write <= addr_write + 1'b1;
      if (oFull) addr_write <= 9'b0;
    end
