            EX_Movn           <= 1'b0;
            EX_Movz           <= 1'b0;
            EX_LLSC           <= 1'b0;
            EX_MemRead        <= 1'b0;
            EX_MemWrite       <= 1'b0;
            EX_MemByte        <= 1'b0;
            EX_MemHalf        <= 1'b0;
