            EX_Left           <= 1'b0;
            EX_Right          <= 1'b0;
            EX_RegWrite       <= 1'b0;
            EX_MemtoReg       <= 1'b0;
            EX_ReverseEndian  <= 1'b0;
            EX_RestartPC      <= 32'b0;
            EX_IsBDS          <= 1'b0;
            EX_Trap           <= 1'b0;
            EX_TrapCond       <= 1'b0;
            EX_EX_CanErr      <= 1'b0;
            EX_M_CanErr       <= 1'b0;
            EX_ReadData1      <= 32'b0;
            EX_ReadData2      <= 32'b0;
            EX_SignExtImm_pre <= 17'b0;
