module autovcoder_031486 #(
    parameter DATA_WIDTH = 32,
    parameter ADDR_WIDTH = 8
) (
    input clk,

    input wea,
    input [ADDR_WIDTH-1:0] addra,
    input [ADDR_WIDTH-1:0] addrb,
    input [DATA_WIDTH-1:0] dia,
    output [DATA_WIDTH-1:0] dob
);

  localparam ADDR_P1 = ADDR_WIDTH + 1;
  localparam DATA_MSB = DATA_WIDTH - 1;
  localparam ADDR_MSB = ADDR_WIDTH - 1;
  localparam DEPTH = 2 ** ADDR_WIDTH;

  (* ram_style = "block" *) reg [DATA_MSB:0] ram[DEPTH-1:0];

  reg [ADDR_MSB:0] addra_d;
  reg [ADDR_MSB:0] addrb_d;
  reg wea_d;
  reg [DATA_MSB:0] dia_d;
  reg [DATA_MSB:0] dob_d;
  reg [DATA_MSB:0] ram_pipe;
  assign dob = dob_d;

  integer i;
  initial begin
    for (i = 0; i < DEPTH; i = i + 1) begin
      ram[i] = 0;
    end
  end

  // port a
  always @(posedge clk) begin
    if (wea_d == 1'b1) begin
      ram[addra_d] <= dia_d;
    end
    dia_d   <= dia;
    addra_d <= addra;
    wea_d   <= wea;
  end

  // port b
  always @(posedge clk) begin
    addrb_d <= addrb;
    ram_pipe <= ram[addrb_d];
    dob_d <= ram_pipe;
  end

endmodule

