module origen_055431 #(
    parameter width = 4,
    parameter height = 8,
    parameter ptr_width = 3
)(
    input wire clk,
    input wire rst,
    input wire [width-1:0] data_in,
    input wire write,
    input wire read,
    output reg [width-1:0] data_out,
    output wire full,
    output wire empty
);

    reg [width-1:0] memory [0:height-1];
    reg [ptr_width-1:0] read_ptr, write_ptr;
    reg [ptr_width:0] diff;
    reg empty_r, empty_r_r, full_r, full_r_r;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            read_ptr <= 0;
            write_ptr <= 0;
            diff <= 0;
            empty_r <= 1'b1;
            empty_r_r <= 1'b1;
            full_r <= 1'b0;
            full_r_r <= 1'b0;
        end else begin
            empty_r_r <= empty_r;
            full_r_r <= full_r;

            if (write && !full && (!read || empty)) begin
                memory[write_ptr] <= data_in;
                write_ptr <= (write_ptr + 1) % height;
                diff <= diff + 1;
            end

            if (read && !empty && (!write || full)) begin
                data_out <= memory[read_ptr];
                read_ptr <= (read_ptr + 1) % height;
                diff <= diff - 1;
            end

            empty_r <= (diff == 0);
            full_r <= (diff == height - 1);
        end
    end

    assign empty = empty_r && empty_r_r;
    assign full = full_r && full_r_r;

endmodule

files.autovcoder_099638.v:
module autovcoder_099638 (
    clk_i,
    corr_i,
    max_o
);

  parameter NUM_CORR = 16;
  parameter NUM_BITS = 12;
  input clk_i;
  input [NUM_CORR*NUM_BITS-1:0] corr_i;
  output [NUM_BITS-1:0] max_o;

  // Outputs the ceiling of log2(number). If value=2,
  // for instance, then
  // i = 0 : 1<2, so loop executes (clogb2 = 1)
  // i = 1 : 2!<2, so loop does not execute, and clogb2 returns 1.
  function integer clogb2;
    input [31:0] value;
    integer i;
    begin
      clogb2 = 0;
      for (i = 0; 2 ** i < value; i = i + 1) clogb2 = i + 1;
    end
  endfunction

  localparam NUM_STAGES = clogb2(NUM_CORR);
  localparam NUM_CORR_B2 = 2 ** NUM_STAGES;

  // We only use half of these.
  wire [NUM_BITS-1:0] corrs[NUM_STAGES:0][NUM_CORR_B2-1:0];
  generate
    genvar i, j, k, l;
    for (i = 0; i < NUM_CORR_B2; i = i + 1) begin : VEC
      if (i < NUM_CORR) assign corrs[0][i] = corr_i[NUM_BITS*i+:NUM_BITS];
      else assign corrs[0][i] = {NUM_BITS{1'b0}};
    end
    for (j = 0; j < NUM_STAGES; j = j + 1) begin : COMPARE
      // Number of output stages is half our input number.
      reg [NUM_BITS-1:0] stage_max[2**(NUM_STAGES-j-1)-1:0];
      for (k = 0; k < 2 ** (NUM_STAGES - j - 1); k = k + 1) begin : LOOP
        initial stage_max[k] <= {NUM_BITS{1'b0}};
        always @(posedge clk_i) begin : STAGE_COMPARE
          if (corrs[j][2*k] > corrs[j][2*k+1]) stage_max[k] <= corrs[j][2*k];
          else stage_max[k] <= corrs[j][2*k+1];
        end
        assign corrs[j+1][k] = stage_max[k];
      end
    end
  endgenerate
  assign max_o = corrs[NUM_STAGES][0];

endmodule

files.autovcoder_081227.v:
module autovcoder_081227 (
    y,
    x,
    clk,
    reset
);
  output y;
  input x;
  input clk;
  input reset;
  reg y;
  parameter  // state identifiers
  start = 3'b000, id1 = 3'b001, id10 = 3'b011, id101 = 3'b010, id1010 = 3'b110;  // signal found
  reg [2:0] E1;  // current state variables
  reg [2:0] E2;  // next state logic output
  // next state logic
  always @(x or E1) begin
    case (E1)
      start:
      if (x) E2 = id1;
      else E2 = start;
      id1:
      if (x) E2 = start;
      else E2 = id10;
      id10:
      if (x) E2 = id101;
      else E2 = start;
      id101:
      if (x) E2 = id1;
      else E2 = id1010;
      id1010:
      if (x) E2 = id1;
      else E2 = start;
      default:  // undefined statee
      E2 = 3'bxxx;
    endcase
  end  // always at signal or state changing
  // state variables
  always @(posedge clk or negedge reset) begin
    if (reset) E1 = E2;  // updates current state
    else E1 = 0;  // reset
  end  // always at signal changing
  // output logic
  always @(E1) begin
    y = E1[2];  // first bit of state value (MOORE indicator)
  end  // always at state changing
endmodule

