function [31:0] calculate_crc;
    input [7:0] data_in;
    input [31:0] crc_state;

    reg [31:0] crc_result;
    integer i;

    begin
        crc_result = crc_state;
        for (i = 0; i < 8; i = i + 1) begin
            if ((crc_result[31] ^ data_in[i]) == 1) begin
                crc_result = (crc_result << 1) ^ 32'h04C11DB7;
            end else begin
                crc_result = crc_result << 1;
            end
        end
        calculate_crc = crc_result;
    end
