    input_port_PopNB_mioi_ivld
);
  input clk;
  input rst;
  output [136:0] input_port_PopNB_mioi_idat_mxwt;
  output input_port_PopNB_mioi_ivld_mxwt;
  input input_port_PopNB_mioi_biwt;
