            img_rd <= 1'b1;
            grad_wr <= 1'b0;
            grad_rd <= 1'b0;
            img_addr <= 16'd0;
            grad_addr <= 16'd0;
            img_addr_reg <= 16'd0;
            grad_addr_reg <= 16'd0;
        end else begin
            if (init) begin
                x_2 <= img_di;
                init <= 1'b0;
                rd <= 1'b1;
                img_addr <= 16'd1;
            end else if (rd) begin
                if (ctrl) begin
                    x_3 <= img_di;
                    rd <= 1'b0;
                    cal <= 1'b1;
