                end
            end else if (cal) begin
                grad_do <= {gx[9:0], gy[9:0]};
                cal <= 1'b0;
                wr <= 1'b1;
                grad_wr <= 1'b1;
            end else if (wr) begin
                grad_wr <= 1'b0;
                wr <= 1'b0;
                rd <= 1'b1;
                ctrl <= 1'b0;
                img_rd <= 1'b1;
