);

reg [3:0] Sreg, Snext;

localparam INIT = 4'd0,
           LOAD_SLOW1 = 4'd1, LOAD_SLOW2 = 4'd2,
           LOAD_FAST1 = 4'd3, LOAD_FAST2 = 4'd4,
           WAIT = 4'd5,
           SEND = 4'd6,
           LOAD_FAST_INIT1 = 4'd7, LOAD_FAST_INIT2 = 4'd8;

always @(posedge CLOCK or posedge RESET) begin
    if (RESET)
        Sreg <= INIT;
    else
        Sreg <= Snext;
end

always @(*) begin
    case (Sreg)
        INIT:
            if (Data_RDY)
                Snext = LOAD_SLOW1;
            else
                Snext = INIT;
        LOAD_SLOW1:
            Snext = LOAD_SLOW2;
        LOAD_SLOW2:
            if (loaded)
                Snext = LOAD_FAST_INIT1;
            else
                Snext = LOAD_SLOW2;
        LOAD_FAST_INIT1:
            Snext = LOAD_FAST_INIT2;
        LOAD_FAST_INIT2:
