                Snext = LOAD_FAST2;
        WAIT:
            if (interpolate_count == 1 || shift_done)
                Snext = SEND;
            else
                Snext = WAIT;
        SEND:
            Snext = INIT;
        default:
            Snext = INIT;
    endcase
end

always @(*) begin
    // Default output values
    interpolate_count_ENP = 1'b0;
    CIC_en = 1'b0;
    pulse_slow = 1'b0;
