            load_result_slow = 1'b1;
        LOAD_SLOW2:
            load_result_slow = 1'b1;
        LOAD_FAST_INIT1:
            ;
        LOAD_FAST_INIT2:
            ;
        LOAD_FAST1:
            load_result_fast = 1'b1;
        LOAD_FAST2:
            load_result_fast = 1'b1;
        WAIT:
            ;
        SEND:
            begin
                interpolate_count_ENP = 1'b1;
                CIC_en = 1'b1;
                pulse_slow = 1'b1;
                pulse_fast = 1'b1;
                data_select = 1'b1;
