module origen_134837 #(
    parameter INPUT_WIDTH = 17,
    parameter OUTPUT_WIDTH = 9,
    parameter EXCEPTION_WIDTH = 4,
    parameter ROUNDING_MODE_WIDTH = 3,
    parameter floatControlWidth = 5
) (
