    input wire [ROUNDING_MODE_WIDTH-1:0] roundingMode,
    input wire [floatControlWidth-1:0] control,
    output reg inReady,
    output reg outValid,
    output reg [OUTPUT_WIDTH-1:0] out,
    output reg [EXCEPTION_WIDTH-1:0] exceptionFlags
);

